using ContosoUniversity.Models;
using ContosoUniversity.Services;

namespace ContosoUniversity.Tests.Services
{
    [TestClass]
    public sealed class NotificationServiceTests
    {
        private NotificationService _sut = null!;

        [TestInitialize]
        public void Setup()
        {
            _sut = new NotificationService();
        }

        [TestCleanup]
        public void Cleanup()
        {
            _sut.Dispose();
        }

        [TestMethod]
        public void SendNotification_WithDisplayName_EnqueuesNotification()
        {
            // Act
            _sut.SendNotification("Student", "1", "John Doe", EntityOperation.CREATE, "Admin");

            // Assert
            var notification = _sut.ReceiveNotification();
            Assert.IsNotNull(notification);
            Assert.AreEqual("Student", notification.EntityType);
            Assert.AreEqual("1", notification.EntityId);
            Assert.AreEqual("CREATE", notification.Operation);
            Assert.AreEqual("Admin", notification.CreatedBy);
            Assert.IsFalse(notification.IsRead);
            Assert.IsTrue(notification.Message.Contains("John Doe"));
        }

        [TestMethod]
        public void SendNotification_WithoutDisplayName_UsesEntityId()
        {
            // Act
            _sut.SendNotification("Course", "42", null, EntityOperation.UPDATE);

            // Assert
            var notification = _sut.ReceiveNotification();
            Assert.IsNotNull(notification);
            Assert.IsTrue(notification.Message.Contains("ID: 42"));
        }

        [TestMethod]
        public void SendNotification_WithoutUserName_DefaultsToSystem()
        {
            // Act
            _sut.SendNotification("Student", "1", EntityOperation.CREATE);

            // Assert
            var notification = _sut.ReceiveNotification();
            Assert.IsNotNull(notification);
            Assert.AreEqual("System", notification.CreatedBy);
        }

        [TestMethod]
        [DataRow(EntityOperation.CREATE, "has been created")]
        [DataRow(EntityOperation.UPDATE, "has been updated")]
        [DataRow(EntityOperation.DELETE, "has been deleted")]
        public void SendNotification_GeneratesCorrectMessage_ForEachOperation(EntityOperation operation, string expectedPhrase)
        {
            // Act
            _sut.SendNotification("Department", "5", "Engineering", operation);

            // Assert
            var notification = _sut.ReceiveNotification();
            Assert.IsNotNull(notification);
            Assert.IsTrue(notification.Message.Contains(expectedPhrase),
                $"Expected message to contain '{expectedPhrase}' but got '{notification.Message}'");
        }

        [TestMethod]
        public void ReceiveNotification_WhenQueueEmpty_ReturnsNull()
        {
            // Act
            var result = _sut.ReceiveNotification();

            // Assert
            Assert.IsNull(result);
        }

        [TestMethod]
        public void ReceiveNotification_DequeueFIFO()
        {
            // Arrange
            _sut.SendNotification("Student", "1", "First", EntityOperation.CREATE);
            _sut.SendNotification("Student", "2", "Second", EntityOperation.CREATE);

            // Act
            var first = _sut.ReceiveNotification();
            var second = _sut.ReceiveNotification();

            // Assert
            Assert.IsNotNull(first);
            Assert.IsNotNull(second);
            Assert.AreEqual("1", first.EntityId);
            Assert.AreEqual("2", second.EntityId);
        }

        [TestMethod]
        public void SendNotification_OverloadWithoutDisplayName_Works()
        {
            // Act - uses the two-parameter overload (no display name)
            _sut.SendNotification("Instructor", "10", EntityOperation.DELETE, "TestUser");

            // Assert
            var notification = _sut.ReceiveNotification();
            Assert.IsNotNull(notification);
            Assert.AreEqual("Instructor", notification.EntityType);
            Assert.AreEqual("10", notification.EntityId);
            Assert.AreEqual("DELETE", notification.Operation);
            Assert.AreEqual("TestUser", notification.CreatedBy);
        }

        [TestMethod]
        public void SendNotification_SetsCreatedAtTimestamp()
        {
            // Arrange
            var before = DateTime.Now.AddSeconds(-1);

            // Act
            _sut.SendNotification("Student", "1", EntityOperation.CREATE);

            // Assert
            var notification = _sut.ReceiveNotification();
            Assert.IsNotNull(notification);
            Assert.IsTrue(notification.CreatedAt >= before);
            Assert.IsTrue(notification.CreatedAt <= DateTime.Now.AddSeconds(1));
        }

        [TestMethod]
        public void Dispose_DoesNotThrow()
        {
            // Act & Assert - should not throw
            _sut.Dispose();
        }

        [TestMethod]
        public void MarkAsRead_DoesNotThrow()
        {
            // MarkAsRead is a no-op for in-memory implementation
            _sut.MarkAsRead(42);
        }
    }
}

