namespace ContosoUniversity.Tests
{
    [TestClass]
    public sealed class PaginatedListTests
    {
        [TestMethod]
        public void Constructor_SetsPageIndex()
        {
            // Arrange
            var items = new List<string> { "a", "b", "c" };

            // Act
            var result = new PaginatedList<string>(items, 10, 2, 3);

            // Assert
            Assert.AreEqual(2, result.PageIndex);
        }

        [TestMethod]
        public void Constructor_CalculatesTotalPages()
        {
            // Arrange
            var items = new List<string> { "a", "b", "c" };

            // Act
            var result = new PaginatedList<string>(items, 10, 1, 3);

            // Assert - 10 items / 3 per page = ceil(3.33) = 4
            Assert.AreEqual(4, result.TotalPages);
        }

        [TestMethod]
        [DataRow(10, 5, 2)]
        [DataRow(7, 3, 3)]
        [DataRow(1, 1, 1)]
        [DataRow(0, 5, 0)]
        public void Constructor_TotalPages_CalculatedCorrectly(int count, int pageSize, int expectedTotalPages)
        {
            // Act
            var result = new PaginatedList<int>(new List<int>(), count, 1, pageSize);

            // Assert
            Assert.AreEqual(expectedTotalPages, result.TotalPages);
        }

        [TestMethod]
        public void Constructor_AddsItemsToList()
        {
            // Arrange
            var items = new List<int> { 1, 2, 3 };

            // Act
            var result = new PaginatedList<int>(items, 10, 1, 5);

            // Assert
            Assert.AreEqual(3, result.Count);
            CollectionAssert.AreEqual(items, result.ToList());
        }

        [TestMethod]
        public void HasPreviousPage_FirstPage_ReturnsFalse()
        {
            // Act
            var result = new PaginatedList<int>(new List<int>(), 10, 1, 5);

            // Assert
            Assert.IsFalse(result.HasPreviousPage);
        }

        [TestMethod]
        public void HasPreviousPage_SecondPage_ReturnsTrue()
        {
            // Act
            var result = new PaginatedList<int>(new List<int>(), 10, 2, 5);

            // Assert
            Assert.IsTrue(result.HasPreviousPage);
        }

        [TestMethod]
        public void HasNextPage_LastPage_ReturnsFalse()
        {
            // Act - 10 items, page size 5 => 2 total pages, we're on page 2
            var result = new PaginatedList<int>(new List<int>(), 10, 2, 5);

            // Assert
            Assert.IsFalse(result.HasNextPage);
        }

        [TestMethod]
        public void HasNextPage_NotLastPage_ReturnsTrue()
        {
            // Act - 10 items, page size 5 => 2 total pages, we're on page 1
            var result = new PaginatedList<int>(new List<int>(), 10, 1, 5);

            // Assert
            Assert.IsTrue(result.HasNextPage);
        }

        [TestMethod]
        public void Create_ReturnsCorrectPage()
        {
            // Arrange
            var source = Enumerable.Range(1, 20).AsQueryable();

            // Act - page 2, page size 5 => items 6-10
            var result = PaginatedList<int>.Create(source, 2, 5);

            // Assert
            Assert.AreEqual(2, result.PageIndex);
            Assert.AreEqual(4, result.TotalPages);
            Assert.AreEqual(5, result.Count);
            Assert.AreEqual(6, result[0]);
            Assert.AreEqual(10, result[4]);
        }

        [TestMethod]
        public void Create_FirstPage_ReturnsFirstItems()
        {
            // Arrange
            var source = Enumerable.Range(1, 15).AsQueryable();

            // Act
            var result = PaginatedList<int>.Create(source, 1, 5);

            // Assert
            Assert.AreEqual(1, result.PageIndex);
            Assert.AreEqual(3, result.TotalPages);
            Assert.AreEqual(5, result.Count);
            Assert.AreEqual(1, result[0]);
        }

        [TestMethod]
        public void Create_LastPage_ReturnRemainingItems()
        {
            // Arrange - 7 items, page size 3, page 3 => items 7
            var source = Enumerable.Range(1, 7).AsQueryable();

            // Act
            var result = PaginatedList<int>.Create(source, 3, 3);

            // Assert
            Assert.AreEqual(3, result.PageIndex);
            Assert.AreEqual(1, result.Count);
            Assert.AreEqual(7, result[0]);
        }

        [TestMethod]
        public void Create_EmptySource_ReturnsEmptyList()
        {
            // Arrange
            var source = Enumerable.Empty<int>().AsQueryable();

            // Act
            var result = PaginatedList<int>.Create(source, 1, 10);

            // Assert
            Assert.AreEqual(0, result.Count);
            Assert.AreEqual(0, result.TotalPages);
            Assert.IsFalse(result.HasPreviousPage);
            Assert.IsFalse(result.HasNextPage);
        }
    }
}

