using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;
using Microsoft.AspNetCore.Mvc.ViewFeatures;

namespace ContosoUniversity.Tests.Controllers
{
    [TestClass]
    public sealed class StudentsControllerTests
    {
        private SchoolContext _context = null!;
        private StudentsController _controller = null!;

        [TestInitialize]
        public void Setup()
        {
            _context = TestDbContextFactory.Create();
            _controller = new StudentsController(_context);

            // Set up TempData for controller
            _controller.TempData = new TempDataDictionary(
                new DefaultHttpContext(), 
                new Mock<ITempDataProvider>().Object);
        }

        [TestCleanup]
        public void Cleanup()
        {
            _controller.Dispose();
            _context.Dispose();
        }

        private void SeedStudents()
        {
            _context.Students.AddRange(
                new Student { FirstMidName = "Carson", LastName = "Alexander", EnrollmentDate = new DateTime(2010, 9, 1) },
                new Student { FirstMidName = "Meredith", LastName = "Alonso", EnrollmentDate = new DateTime(2012, 9, 1) },
                new Student { FirstMidName = "Arturo", LastName = "Anand", EnrollmentDate = new DateTime(2013, 9, 1) },
                new Student { FirstMidName = "Gytis", LastName = "Barzdukas", EnrollmentDate = new DateTime(2012, 9, 1) },
                new Student { FirstMidName = "Yan", LastName = "Li", EnrollmentDate = new DateTime(2012, 9, 1) }
            );
            _context.SaveChanges();
        }

        #region Index Tests

        [TestMethod]
        public void Index_NoParameters_ReturnsViewWithStudents()
        {
            // Arrange
            SeedStudents();

            // Act
            var result = _controller.Index(null, null, null, null) as ViewResult;

            // Assert
            Assert.IsNotNull(result);
            var model = result.Model as PaginatedList<Student>;
            Assert.IsNotNull(model);
            Assert.AreEqual(5, model.Count);
        }

        [TestMethod]
        public void Index_DefaultSort_OrdersByLastNameAscending()
        {
            // Arrange
            SeedStudents();

            // Act
            var result = _controller.Index(null, null, null, null) as ViewResult;

            // Assert
            var model = result!.Model as PaginatedList<Student>;
            Assert.IsNotNull(model);
            Assert.AreEqual("Alexander", model[0].LastName);
            Assert.AreEqual("Alonso", model[1].LastName);
        }

        [TestMethod]
        public void Index_NameDescSort_OrdersByLastNameDescending()
        {
            // Arrange
            SeedStudents();

            // Act
            var result = _controller.Index("name_desc", null, null, null) as ViewResult;

            // Assert
            var model = result!.Model as PaginatedList<Student>;
            Assert.IsNotNull(model);
            Assert.AreEqual("Li", model[0].LastName);
        }

        [TestMethod]
        public void Index_DateSort_OrdersByEnrollmentDateAscending()
        {
            // Arrange
            SeedStudents();

            // Act
            var result = _controller.Index("Date", null, null, null) as ViewResult;

            // Assert
            var model = result!.Model as PaginatedList<Student>;
            Assert.IsNotNull(model);
            Assert.AreEqual(new DateTime(2010, 9, 1), model[0].EnrollmentDate);
        }

        [TestMethod]
        public void Index_DateDescSort_OrdersByEnrollmentDateDescending()
        {
            // Arrange
            SeedStudents();

            // Act
            var result = _controller.Index("date_desc", null, null, null) as ViewResult;

            // Assert
            var model = result!.Model as PaginatedList<Student>;
            Assert.IsNotNull(model);
            Assert.AreEqual(new DateTime(2013, 9, 1), model[0].EnrollmentDate);
        }

        [TestMethod]
        public void Index_SearchString_FiltersStudentsByLastName()
        {
            // Arrange
            SeedStudents();

            // Act
            var result = _controller.Index(null, null, "Alexander", null) as ViewResult;

            // Assert
            var model = result!.Model as PaginatedList<Student>;
            Assert.IsNotNull(model);
            Assert.AreEqual(1, model.Count);
            Assert.AreEqual("Alexander", model[0].LastName);
        }

        [TestMethod]
        public void Index_SearchString_FiltersStudentsByFirstName()
        {
            // Arrange
            SeedStudents();

            // Act
            var result = _controller.Index(null, null, "Carson", null) as ViewResult;

            // Assert
            var model = result!.Model as PaginatedList<Student>;
            Assert.IsNotNull(model);
            Assert.AreEqual(1, model.Count);
            Assert.AreEqual("Carson", model[0].FirstMidName);
        }

        [TestMethod]
        public void Index_SearchStringProvided_ResetsPageTo1()
        {
            // Arrange
            SeedStudents();

            // Act
            var result = _controller.Index(null, null, "A", 3) as ViewResult;

            // Assert
            var model = result!.Model as PaginatedList<Student>;
            Assert.IsNotNull(model);
            Assert.AreEqual(1, model.PageIndex);
        }

        [TestMethod]
        public void Index_NullSearchWithCurrentFilter_UsesCurrentFilter()
        {
            // Arrange
            SeedStudents();

            // Act
            var result = _controller.Index(null, "Li", null, null) as ViewResult;

            // Assert
            var model = result!.Model as PaginatedList<Student>;
            Assert.IsNotNull(model);
            Assert.AreEqual(1, model.Count);
            Assert.AreEqual("Li", model[0].LastName);
        }

        [TestMethod]
        public void Index_SetsViewBagSortParameters()
        {
            // Arrange
            SeedStudents();

            // Act
            var result = _controller.Index(null, null, null, null) as ViewResult;

            // Assert
            Assert.AreEqual("name_desc", _controller.ViewBag.NameSortParm);
            Assert.AreEqual("Date", _controller.ViewBag.DateSortParm);
        }

        [TestMethod]
        public void Index_WithSortOrder_SetsCorrectDateSortParm()
        {
            // Arrange
            SeedStudents();

            // Act
            _controller.Index("Date", null, null, null);

            // Assert
            Assert.AreEqual("date_desc", _controller.ViewBag.DateSortParm);
        }

        #endregion

        #region Details Tests

        [TestMethod]
        public void Details_NullId_ReturnsBadRequest()
        {
            // Act
            var result = _controller.Details(null) as StatusCodeResult;

            // Assert
            Assert.IsNotNull(result);
            Assert.AreEqual(400, result.StatusCode);
        }

        [TestMethod]
        public void Details_ValidId_ReturnsViewWithStudent()
        {
            // Arrange
            SeedStudents();
            var studentId = _context.Students.First().ID;

            // Act
            var result = _controller.Details(studentId) as ViewResult;

            // Assert
            Assert.IsNotNull(result);
            var model = result.Model as Student;
            Assert.IsNotNull(model);
            Assert.AreEqual(studentId, model.ID);
        }

        #endregion

        #region Create Tests

        [TestMethod]
        public void Create_Get_ReturnsViewWithDefaultDate()
        {
            // Act
            var result = _controller.Create() as ViewResult;

            // Assert
            Assert.IsNotNull(result);
            var model = result.Model as Student;
            Assert.IsNotNull(model);
            Assert.AreEqual(DateTime.Today, model.EnrollmentDate);
        }

        [TestMethod]
        public void Create_Post_ValidStudent_RedirectsToIndex()
        {
            // Arrange
            var student = new Student
            {
                FirstMidName = "Test",
                LastName = "Student",
                EnrollmentDate = new DateTime(2023, 9, 1)
            };

            // Act
            var result = _controller.Create(student) as RedirectToActionResult;

            // Assert
            Assert.IsNotNull(result);
            Assert.AreEqual("Index", result.ActionName);
        }

        [TestMethod]
        public void Create_Post_ValidStudent_SavesStudentToDatabase()
        {
            // Arrange
            var student = new Student
            {
                FirstMidName = "Test",
                LastName = "Student",
                EnrollmentDate = new DateTime(2023, 9, 1)
            };

