using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Models.SchoolViewModels;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;
using Microsoft.AspNetCore.Mvc.ViewFeatures;

namespace ContosoUniversity.Tests.Controllers
{
    [TestClass]
    public sealed class HomeControllerTests
    {
        private SchoolContext _context = null!;
        private HomeController _controller = null!;

        [TestInitialize]
        public void Setup()
        {
            _context = TestDbContextFactory.Create();
            _controller = new HomeController(_context);

            _controller.TempData = new TempDataDictionary(
                new DefaultHttpContext(),
                new Mock<ITempDataProvider>().Object);
        }

        [TestCleanup]
        public void Cleanup()
        {
            _controller.Dispose();
            _context.Dispose();
        }

        [TestMethod]
        public void Index_ReturnsView()
        {
            // Act
            var result = _controller.Index() as ViewResult;

            // Assert
            Assert.IsNotNull(result);
        }

        [TestMethod]
        public void About_ReturnsViewWithEnrollmentGroups()
        {
            // Arrange
            _context.Students.AddRange(
                new Student { FirstMidName = "A", LastName = "B", EnrollmentDate = new DateTime(2020, 9, 1) },
                new Student { FirstMidName = "C", LastName = "D", EnrollmentDate = new DateTime(2020, 9, 1) },
                new Student { FirstMidName = "E", LastName = "F", EnrollmentDate = new DateTime(2021, 9, 1) }
            );
            _context.SaveChanges();

            // Act
            var result = _controller.About() as ViewResult;

            // Assert
            Assert.IsNotNull(result);
            var model = result.Model as List<EnrollmentDateGroup>;
            Assert.IsNotNull(model);
            Assert.AreEqual(2, model.Count);

            var group2020 = model.Single(g => g.EnrollmentDate == new DateTime(2020, 9, 1));
            Assert.AreEqual(2, group2020.StudentCount);

            var group2021 = model.Single(g => g.EnrollmentDate == new DateTime(2021, 9, 1));
            Assert.AreEqual(1, group2021.StudentCount);
        }

        [TestMethod]
        public void About_NoStudents_ReturnsEmptyList()
        {
            // Act
            var result = _controller.About() as ViewResult;

            // Assert
            Assert.IsNotNull(result);
            var model = result.Model as List<EnrollmentDateGroup>;
            Assert.IsNotNull(model);
            Assert.AreEqual(0, model.Count);
        }

        [TestMethod]
        public void Contact_ReturnsViewWithMessage()
        {
            // Act
            var result = _controller.Contact() as ViewResult;

            // Assert
            Assert.IsNotNull(result);
            Assert.AreEqual("Your contact page.", _controller.ViewBag.Message);
        }

        [TestMethod]
        public void Error_ReturnsView()
        {
            // Act
            var result = _controller.Error() as ViewResult;

            // Assert
            Assert.IsNotNull(result);
        }

        [TestMethod]
        public void Unauthorized_ReturnsViewWithMessage()
        {
            // Act
            var result = _controller.Unauthorized() as ViewResult;

