using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;
using Microsoft.AspNetCore.Mvc.ViewFeatures;

namespace ContosoUniversity.Tests.Controllers
{
    [TestClass]
    public sealed class NotificationsControllerTests
    {
        private SchoolContext _context = null!;
        private NotificationsController _controller = null!;

        [TestInitialize]
        public void Setup()
        {
            _context = TestDbContextFactory.Create();
            _controller = new NotificationsController(_context);

            _controller.TempData = new TempDataDictionary(
                new DefaultHttpContext(),
                new Mock<ITempDataProvider>().Object);
        }

        [TestCleanup]
        public void Cleanup()
        {
            _controller.Dispose();
            _context.Dispose();
        }

        [TestMethod]
        public void GetNotifications_WhenEmpty_ReturnsSuccessWithEmptyList()
        {
            // Act
            var result = _controller.GetNotifications();

            // Assert
            Assert.IsNotNull(result);
            var value = result.Value as dynamic;
            Assert.IsNotNull(value);
        }

        [TestMethod]
        public void GetNotifications_AfterSendingNotification_ReturnsNotification()
        {
            // Arrange - send a notification via a student creation
            var student = new Student
            {
                FirstMidName = "Test",
                LastName = "User",
                EnrollmentDate = new DateTime(2023, 1, 1)
            };
            _context.Students.Add(student);
            _context.SaveChanges();

            // Use a separate controller to send notification (simulating real flow)
            using var studentsController = new StudentsController(_context);
            studentsController.TempData = new TempDataDictionary(
                new DefaultHttpContext(),
                new Mock<ITempDataProvider>().Object);

            // The base controller's SendEntityNotification enqueues to the static queue
            // So when we call GetNotifications it should find something in the shared queue

            // Act
            var result = _controller.GetNotifications();

            // Assert
            Assert.IsNotNull(result);
        }

        [TestMethod]
        public void MarkAsRead_ReturnsSuccess()
        {
            // Act
            var result = _controller.MarkAsRead(1);

            // Assert
            Assert.IsNotNull(result);
        }

        [TestMethod]
        public void Index_ReturnsView()
        {
            // Act
            var result = _controller.Index() as ViewResult;

            // Assert
            Assert.IsNotNull(result);
        }
    }
}

