using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;
using Microsoft.AspNetCore.Mvc.ViewFeatures;

namespace ContosoUniversity.Tests.Controllers
{
    [TestClass]
    public sealed class InstructorsControllerTests
    {
        private SchoolContext _context = null!;
        private InstructorsController _controller = null!;

        [TestInitialize]
        public void Setup()
        {
            _context = TestDbContextFactory.Create();
            _controller = new InstructorsController(_context);

            _controller.TempData = new TempDataDictionary(
                new DefaultHttpContext(),
                new Mock<ITempDataProvider>().Object);
        }

        [TestCleanup]
        public void Cleanup()
        {
            _controller.Dispose();
            _context.Dispose();
        }

        private void SeedInstructors()
        {
            var instructors = new[]
            {
                new Instructor { FirstMidName = "Kim", LastName = "Abercrombie", HireDate = new DateTime(1995, 3, 11), CourseAssignments = new List<CourseAssignment>() },
                new Instructor { FirstMidName = "Fadi", LastName = "Fakhouri", HireDate = new DateTime(2002, 7, 6), CourseAssignments = new List<CourseAssignment>() },
                new Instructor { FirstMidName = "Roger", LastName = "Harui", HireDate = new DateTime(1998, 7, 1), CourseAssignments = new List<CourseAssignment>() }
            };
            _context.Instructors.AddRange(instructors);
            _context.SaveChanges();

            // Add an office assignment
            _context.OfficeAssignments.Add(new OfficeAssignment
            {
                InstructorID = instructors[1].ID,
                Location = "Smith 17"
            });
            _context.SaveChanges();

            // Add a department
            var dept = new Department { Name = "Engineering", Budget = 350000, StartDate = new DateTime(2007, 9, 1) };
            _context.Departments.Add(dept);
            _context.SaveChanges();

            // Add courses
            _context.Courses.AddRange(
                new Course { CourseID = 1050, Title = "Chemistry", Credits = 3, DepartmentID = dept.DepartmentID, Enrollments = new List<Enrollment>() },
                new Course { CourseID = 4022, Title = "Microeconomics", Credits = 3, DepartmentID = dept.DepartmentID, Enrollments = new List<Enrollment>() }
            );
            _context.SaveChanges();

            // Assign a course to the first instructor
            _context.CourseAssignments.Add(new CourseAssignment
            {
                InstructorID = instructors[0].ID,
                CourseID = 1050
            });
            _context.SaveChanges();
        }

        #region Index Tests

        [TestMethod]
        public void Index_NoParameters_ReturnsViewWithAllInstructors()
        {
            // Arrange
            SeedInstructors();

            // Act
            var result = _controller.Index(null, null) as ViewResult;

            // Assert
            Assert.IsNotNull(result);
            var model = result.Model as InstructorIndexData;
            Assert.IsNotNull(model);
            Assert.AreEqual(3, model.Instructors.Count());
        }

        [TestMethod]
        public void Index_WithInstructorId_SetsCourses()
        {
            // Arrange
            SeedInstructors();
            var instructor = _context.Instructors.First(i => i.LastName == "Abercrombie");

            // Act
            var result = _controller.Index(instructor.ID, null) as ViewResult;

            // Assert
            Assert.IsNotNull(result);
            var model = result.Model as InstructorIndexData;
            Assert.IsNotNull(model);
            Assert.IsNotNull(model.Courses);
            Assert.AreEqual(1, model.Courses.Count());
        }

        #endregion

        #region Details Tests

        [TestMethod]
        public void Details_NullId_ReturnsBadRequest()
        {
            // Act
            var result = _controller.Details(null) as StatusCodeResult;

            // Assert
            Assert.IsNotNull(result);
            Assert.AreEqual(400, result.StatusCode);
        }

        [TestMethod]
        public void Details_InvalidId_ReturnsNotFound()
        {
            // Act
            var result = _controller.Details(999) as NotFoundResult;

            // Assert
            Assert.IsNotNull(result);
        }

        [TestMethod]
        public void Details_ValidId_ReturnsViewWithInstructor()
        {
            // Arrange
            SeedInstructors();
            var instructor = _context.Instructors.First();

            // Act
            var result = _controller.Details(instructor.ID) as ViewResult;

            // Assert
            Assert.IsNotNull(result);
            var model = result.Model as Instructor;
            Assert.IsNotNull(model);
            Assert.AreEqual(instructor.ID, model.ID);
        }

        #endregion

        #region Create Tests

        [TestMethod]
        public void Create_Get_ReturnsViewWithInstructor()
        {
            // Arrange
            SeedInstructors();

            // Act
            var result = _controller.Create() as ViewResult;

            // Assert
            Assert.IsNotNull(result);
            var model = result.Model as Instructor;
            Assert.IsNotNull(model);
            Assert.IsNotNull(model.CourseAssignments);
        }

        [TestMethod]
        public void Create_Post_ValidInstructor_RedirectsToIndex()
        {
            // Arrange
            SeedInstructors();
            var instructor = new Instructor
            {
                FirstMidName = "New",
                LastName = "Instructor",
                HireDate = new DateTime(2023, 1, 1),
                CourseAssignments = new List<CourseAssignment>()
            };

            // Act
            var result = _controller.Create(instructor, null) as RedirectToActionResult;

            // Assert
            Assert.IsNotNull(result);
            Assert.AreEqual("Index", result.ActionName);
        }

        [TestMethod]
        public void Create_Post_ValidInstructor_SavesToDB()
        {
            // Arrange
            SeedInstructors();
            var instructor = new Instructor
            {
                FirstMidName = "New",
                LastName = "Instructor",
                HireDate = new DateTime(2023, 1, 1),
                CourseAssignments = new List<CourseAssignment>()
            };

            // Act
            _controller.Create(instructor, null);

            // Assert
            Assert.AreEqual(4, _context.Instructors.Count());
        }

        [TestMethod]
        public void Create_Post_WithSelectedCourses_AssignsCourses()
        {
            // Arrange
            SeedInstructors();
            var instructor = new Instructor
            {
                FirstMidName = "New",
                LastName = "Instructor",
                HireDate = new DateTime(2023, 1, 1),
                CourseAssignments = new List<CourseAssignment>()
            };
            var selectedCourses = new[] { "1050", "4022" };

            // Act
            _controller.Create(instructor, selectedCourses);

            // Assert
            var saved = _context.Instructors.First(i => i.LastName == "Instructor");
            var assignments = _context.CourseAssignments.Where(ca => ca.InstructorID == saved.ID).ToList();
            Assert.AreEqual(2, assignments.Count);
        }

        [TestMethod]
        public void Create_Post_InvalidModelState_ReturnsView()
        {
            // Arrange
            SeedInstructors();
            var instructor = new Instructor
            {
                FirstMidName = "New",
                LastName = "Instructor",
                HireDate = new DateTime(2023, 1, 1),
                CourseAssignments = new List<CourseAssignment>()
            };
            _controller.ModelState.AddModelError("LastName", "Required");

            // Act
            var result = _controller.Create(instructor, null) as ViewResult;

            // Assert
            Assert.IsNotNull(result);
        }

        #endregion

        #region Edit Tests

        [TestMethod]
        public void Edit_Get_NullId_ReturnsBadRequest()
        {
            // Act
            var result = _controller.Edit((int?)null) as StatusCodeResult;

            // Assert
            Assert.IsNotNull(result);
            Assert.AreEqual(400, result.StatusCode);
        }

        [TestMethod]
        public void Edit_Get_ValidId_ReturnsViewWithInstructor()
        {
            // Arrange
            SeedInstructors();
            var instructor = _context.Instructors.First();

            // Act
            var result = _controller.Edit(instructor.ID) as ViewResult;

            // Assert
            Assert.IsNotNull(result);
            var model = result.Model as Instructor;
            Assert.IsNotNull(model);
            Assert.AreEqual(instructor.ID, model.ID);
        }

        #endregion

        #region Delete Tests

        [TestMethod]
        public void Delete_Get_NullId_ReturnsBadRequest()
        {
            // Act
            var result = _controller.Delete(null) as StatusCodeResult;

            // Assert
            Assert.IsNotNull(result);
            Assert.AreEqual(400, result.StatusCode);
        }

        [TestMethod]
        public void Delete_Get_InvalidId_ReturnsNotFound()
        {
            // Act
            var result = _controller.Delete(999) as NotFoundResult;

            // Assert
            Assert.IsNotNull(result);
        }

        [TestMethod]
        public void Delete_Get_ValidId_ReturnsViewWithInstructor()
        {
            // Arrange
            SeedInstructors();
            var instructor = _context.Instructors.First();

            // Act
            var result = _controller.Delete(instructor.ID) as ViewResult;

            // Assert
            Assert.IsNotNull(result);
            var model = result.Model as Instructor;
            Assert.IsNotNull(model);
        }

        [TestMethod]
        public void DeleteConfirmed_RemovesInstructorAndRedirects()
        {
            // Arrange
            SeedInstructors();
            var instructor = _context.Instructors.First(i => i.LastName == "Abercrombie");
            var initialCount = _context.Instructors.Count();

            // Act
            var result = _controller.DeleteConfirmed(instructor.ID) as RedirectToActionResult;

            // Assert
            Assert.IsNotNull(result);
            Assert.AreEqual("Index", result.ActionName);
            Assert.AreEqual(initialCount - 1, _context.Instructors.Count());
        }

        [TestMethod]
        public void DeleteConfirmed_InstructorIsDepartmentAdmin_ClearsDepartmentAdmin()
        {
            // Arrange
            SeedInstructors();
            var instructor = _context.Instructors.First(i => i.LastName == "Abercrombie");

            // Make this instructor a department admin
            var dept = _context.Departments.First();
            dept.InstructorID = instructor.ID;
            _context.SaveChanges();

            // Act
            _controller.DeleteConfirmed(instructor.ID);

            // Assert
            var updatedDept = _context.Departments.First();
            Assert.IsNull(updatedDept.InstructorID);
        }

        #endregion
    }
}

