using ContosoUniversity.Models;

namespace ContosoUniversity.Tests
{
    [TestClass]
    public sealed class ModelTests
    {
        #region Person / Student / Instructor

        [TestMethod]
        public void Person_FullName_ReturnsLastCommaFirst()
        {
            // Arrange
            var student = new Student
            {
                FirstMidName = "Carson",
                LastName = "Alexander",
                EnrollmentDate = DateTime.Today
            };

            // Act
            var fullName = student.FullName;

            // Assert
            Assert.AreEqual("Alexander, Carson", fullName);
        }

        [TestMethod]
        public void Instructor_FullName_ReturnsLastCommaFirst()
        {
            // Arrange
            var instructor = new Instructor
            {
                FirstMidName = "Kim",
                LastName = "Abercrombie",
                HireDate = DateTime.Today
            };

            // Act & Assert
            Assert.AreEqual("Abercrombie, Kim", instructor.FullName);
        }

        #endregion

        #region Course

        [TestMethod]
        public void Course_Properties_SetCorrectly()
        {
            // Arrange & Act
            var course = new Course
            {
                CourseID = 1050,
                Title = "Chemistry",
                Credits = 3,
                DepartmentID = 1,
                TeachingMaterialImagePath = "/path/to/image.jpg"
            };

            // Assert
            Assert.AreEqual(1050, course.CourseID);
            Assert.AreEqual("Chemistry", course.Title);
            Assert.AreEqual(3, course.Credits);
            Assert.AreEqual(1, course.DepartmentID);
            Assert.AreEqual("/path/to/image.jpg", course.TeachingMaterialImagePath);
        }

        #endregion

        #region Department

        [TestMethod]
        public void Department_Properties_SetCorrectly()
        {
            // Arrange & Act
            var dept = new Department
            {
                DepartmentID = 1,
                Name = "Engineering",
                Budget = 350000m,
                StartDate = new DateTime(2007, 9, 1),
                InstructorID = 5
            };

            // Assert
            Assert.AreEqual(1, dept.DepartmentID);
            Assert.AreEqual("Engineering", dept.Name);
            Assert.AreEqual(350000m, dept.Budget);
            Assert.AreEqual(new DateTime(2007, 9, 1), dept.StartDate);
            Assert.AreEqual(5, dept.InstructorID);
        }

        [TestMethod]
        public void Department_InstructorID_IsNullable()
        {
            // Arrange & Act
            var dept = new Department { Name = "Test", Budget = 0, StartDate = DateTime.Today };

            // Assert
            Assert.IsNull(dept.InstructorID);
        }

        #endregion

        #region Enrollment

        [TestMethod]
        [DataRow(Grade.A)]
        [DataRow(Grade.B)]
        [DataRow(Grade.C)]
        [DataRow(Grade.D)]
        [DataRow(Grade.F)]
        public void Enrollment_Grade_AcceptsAllValues(Grade grade)
        {
            // Arrange & Act
            var enrollment = new Enrollment { Grade = grade };

            // Assert
            Assert.AreEqual(grade, enrollment.Grade);
        }

        [TestMethod]
        public void Enrollment_Grade_IsNullable()
        {
