using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;
using Microsoft.EntityFrameworkCore;

namespace ContosoUniversity.Tests
{
    [TestClass]
    public sealed class DbInitializerTests
    {
        [TestMethod]
        public void Initialize_EmptyDatabase_SeedsData()
        {
            // Arrange
            using var context = TestDbContextFactory.Create();

            // Act
            DbInitializer.Initialize(context);

            // Assert
            Assert.IsTrue(context.Students.Any());
            Assert.IsTrue(context.Instructors.Any());
            Assert.IsTrue(context.Departments.Any());
            Assert.IsTrue(context.Courses.Any());
            Assert.IsTrue(context.Enrollments.Any());
            Assert.IsTrue(context.OfficeAssignments.Any());
            Assert.IsTrue(context.CourseAssignments.Any());
        }

        [TestMethod]
        public void Initialize_AlreadySeeded_DoesNotDuplicate()
        {
            // Arrange
            using var context = TestDbContextFactory.Create();
            DbInitializer.Initialize(context);
            var initialStudentCount = context.Students.Count();

            // Act - run again
            DbInitializer.Initialize(context);

            // Assert
            Assert.AreEqual(initialStudentCount, context.Students.Count());
        }

        [TestMethod]
        public void Initialize_CreatesExpectedStudentCount()
        {
            // Arrange
            using var context = TestDbContextFactory.Create();

            // Act
            DbInitializer.Initialize(context);

            // Assert
            Assert.AreEqual(8, context.Students.Count());
        }

        [TestMethod]
        public void Initialize_CreatesExpectedInstructorCount()
        {
            // Arrange
            using var context = TestDbContextFactory.Create();

            // Act
            DbInitializer.Initialize(context);

            // Assert
            Assert.AreEqual(5, context.Instructors.Count());
        }

        [TestMethod]
        public void Initialize_CreatesExpectedDepartmentCount()
        {
            // Arrange
            using var context = TestDbContextFactory.Create();

            // Act
            DbInitializer.Initialize(context);

            // Assert
            Assert.AreEqual(4, context.Departments.Count());
        }

        [TestMethod]
        public void Initialize_CreatesExpectedCourseCount()
        {
            // Arrange
            using var context = TestDbContextFactory.Create();

            // Act
            DbInitializer.Initialize(context);

            // Assert
            Assert.AreEqual(7, context.Courses.Count());
        }

        [TestMethod]
        public void Initialize_DepartmentsHaveAdministrators()
        {
            // Arrange
            using var context = TestDbContextFactory.Create();

            // Act
            DbInitializer.Initialize(context);

            // Assert
            var departments = context.Departments.ToList();
            Assert.IsTrue(departments.All(d => d.InstructorID != null));
        }

        [TestMethod]
        public void Initialize_EnrollmentsHaveCorrectRelationships()
        {
            // Arrange
            using var context = TestDbContextFactory.Create();

            // Act
            DbInitializer.Initialize(context);

            // Assert
            var enrollments = context.Enrollments.Include(e => e.Student).Include(e => e.Course).ToList();
            Assert.IsTrue(enrollments.All(e => e.Student != null));
            Assert.IsTrue(enrollments.All(e => e.Course != null));
        }
    }
}

